8	#include "wavetable.hpp"
9	#include <uhd/exception.hpp>
10	#include <uhd/usrp/multi_usrp.hpp>
11	#include <uhd/utils/safe_main.hpp>
12	#include <uhd/utils/static.hpp>
13	#include <uhd/utils/thread.hpp>
14	#include <stdint.h>
15	#include <boost/algorithm/string.hpp>
16	#include <boost/format.hpp>
17	#include <boost/program_options.hpp>
18	#include <chrono>
19	#include <cmath>
20	#include <csignal>
21	#include <iostream>
22	#include <string>
23	#include <thread>
24	
25	namespace po = boost::program_options;
26	
27	/***********************************************************************
28	 * Signal handlers
29	 **********************************************************************/
30	static bool stop_signal_called = false;
31	void sig_int_handler(int)
32	{
33	    stop_signal_called = true;
34	}
35	
36	/***********************************************************************
37	 * Main function
38	 **********************************************************************/
39	int UHD_SAFE_MAIN(int argc, char* argv[])
40	{
41	    // program documentation string
42	    const std::string program_doc =
43	        "usage: tx_waveforms [-h] -r RATE -f FREQ [--args ARGS] [--spb SPB]\n"
44	        "                    [--nsamps NSAMPS] [--lo-offset LO_OFFSET] [--gain GAIN]\n"
45	        "                    [--power POWER] [--ant ANT] [--subdev SUBDEV] [--bw BW]\n"
46	        "                    [--wave-type {CONST,SQUARE,RAMP,SINE}]\n"
47	        "                    [--wave-freq WAVE_FREQ] [--wave-ampl WAVE_AMPL]\n"
48	        "                    [--ref {internal,external,mimo,gpsdo}]\n"
49	        "                    [--pps {internal,external,mimo,gpsdo}] [--otw {sc16,sc8}]\n"
50	        "                    [--channels CHANNELS] [--int-n]"
51	        "\n\n"
52	        "This example demonstrates how to stream waveforms from a local data buffer\n"
53	        "using the UHD multi_usrp API. It supports synchronized transmission from\n"
54	        "multiple TX channels and multiple USRP devices.\n"
55	        "\n"
56	        "Key features:\n"
57	        "  - Supports simultaneous transmission from multiple USRP devices and from\n"
58	        "    multiple TX channels.\n"
59	        "  - Streams data from a local buffer directly to the USRP device(s).\n"
60	        "  - Allows selection of waveform types CONST, SINE, SQUARE, and RAMP.\n"
61	        "  - Configurable sample rate, frequency, gain, bandwidth, LO offset,\n"
62	        "    antenna, and more via command-line options.\n"
63	        "  - Handles device clock and time reference selection for synchronization.\n"
64	        "  - Demonstrates timed streaming for synchronized multi-channel/MIMO TX.\n"
65	        "\n"
66	        "Usage examples:\n"
67	        " 1. Single-USRP, single-channel transmission of default waveform (const)\n"
68	        "    at carrier frequency of 2.4 GHz and at a rate of 10 MSps:\n"
69	        "      tx_waveforms --args=\"addr=192.168.10.2\" --freq 2.4e9 --rate 10e6\n"
70	        " 2. Single-USRP, dual-channel transmission of a 1 MHz sine wave\n"
71	        "    at carrier frequency of 2.4 GHz and at a rate of 10 MSps:\n"
72	        "      tx_waveforms --args=\"addr=192.168.10.2\" --freq 2.4e9 --rate 10e6\n"
73	        "                   --channels \"0,1\" --wave-type SINE --wave-freq 1e6\n"
74	        " 3. Two USRPs transmitting a 1 MHz sine wave synchronously on two channels\n"
75	        "    each at a carrier frequency of 2.4 GHz and at a rate of 10 MSps:\n"
76	        "      tx_waveforms --args=\"addr=192.168.10.2,addr=192.168.10.3\" --freq 2.4e9\n"
77	        "                   --rate 10e6 --channels \"0,1,2,3\" --wave-type SINE\n"
78	        "                   --wave-freq 1e6 --pps mimo\n";
79	    // variables to be set by po
80	    std::string args, wave_type, ant, subdev, ref, pps, otw, channel_list;
81	    uint64_t total_num_samps;
82	    size_t spb;
83	    double rate, freq, gain, power, wave_freq, bw, lo_offset;
84	    float ampl;
85	
86	    // setup the program options
87	    po::options_description desc("Allowed options");
88	    // clang-format off
89	    desc.add_options()
90	        ("help,h", "Show this help message and exit.")
91	        ("args", po::value<std::string>(&args)->default_value(""), "USRP device arguments, which holds "
92	            "multiple key value pairs separated by commas."
93	            "\nFor a list of available options for a specific USRP model, see the UHD manual."
94	            "\nFor USRPs supporting multi device operation, this option is also used to define how multiple USRPs are "
95	            "grouped to form a single virtual USRP device."
96	            "\nIf not specified, UHD will connect to the first device it can find."
97	            "\nExamples:"
98	            "\n  --args \"type=b200,serial=30A\" (single device)"
99	            "\n  --args \"addr0=192.168.10.2,addr1=192.168.10.3\" (multiple devices)")
100	        ("spb", po::value<size_t>(&spb)->default_value(0), "Size of the host data buffer that is allocated "
101	            "for each Tx channel."
102	            "\nLarger values may improve throughput. Typical value is between 1,000 and 10,000 samples. If not specified, "
103	            "the size is determined automatically based on the maximum number of samples per buffer supported by the UHD "
104	            "transmit streamer.")
105	        ("nsamps", po::value<uint64_t>(&total_num_samps)->default_value(0), "Total number of samples to "
106	            "transmit. Transmission stops when this number is reached. If set to 0, data will be continuously "
107	            "transmitted.")
108	        ("rate,r", po::value<double>(&rate)->required(), "Sample rate in samples/second.")
109	        ("freq,f", po::value<double>(&freq)->required(), "RF center frequency in Hz.")
110	        ("lo-offset", po::value<double>(&lo_offset)->default_value(0.0),
111	            "LO offset for the frontend in Hz.")
112	        ("gain", po::value<double>(&gain), "Gain for the RF chain in dB. Will be ignored, if --power is "
113	            "specified.")
114	        ("power", po::value<double>(&power), "Transmit power in dBm."
115	            "\nThis option is available only, if it is supported by the USRP. An error is returned otherwise.")
116	        ("ant", po::value<std::string>(&ant), "Antenna port selection string selecting a specific antenna "
117	            "port for USRP daughterboards having multiple antenna connectors per RF channel."
118	            "\nNote: this example program expects a single antenna port selection string which is applied to all channels "
119	            "equally."
120	            "\nExample: --ant \"TX/RX\"")
121	        ("subdev", po::value<std::string>(&subdev), "TX subdevice configuration defining the mapping of "
122	            "channels to RF TX paths."
123	            "\nThe format and available values depend on your USRP model. If not specified, the channels will get numbered "
124	            "in order of the devices, daughterboard slots, and their RF TX channels."
125	            "\nFor typical applications, this default subdevice configuration is sufficient."
126	            "\nNote: this example program expects a single-USRP subdevice configuration which is applied to all USRPs "
127	            "equally, if multiple USRPs are configured."
128	            "\nExample:"
129	            "\nAssume we have an X310 with two CBX daughterboards installed. Then the default channel mapping is:"
130	            "\n  - Ch 0 -> A:0 (1st CBX in slot A, RF TX 0)"
131	            "\n  - Ch 1 -> B:0 (2nd CBX in slot B, RF TX 0)"
132	            "\nSpecifying --subdev=\"B:0 A:0\" would change the channel mapping to:"
133	            "\n  - Ch 0 -> B:0 (2nd CBX in slot B RF TX 0)"
134	            "\n  - Ch 1 -> A:0 (1st CBX in slot A RF TX 0)")
135	        ("bw", po::value<double>(&bw), "Analog frontend filter bandwidth in Hz."
136	            "\nNote that not all USRPs support programmable analog frontend bandwidth and this option might get ignored or "
137	            "throw an error.")
138	        ("wave-type", po::value<std::string>(&wave_type)->default_value("CONST"), "Baseband waveform type to "
139	            "generate."
140	            "\nAvailable types are CONST (real), SQUARE (real), RAMP (real), and SINE (complex)")
141	        ("wave-freq", po::value<double>(&wave_freq)->default_value(0), "Baseband waveform frequency in Hz."
142	            "\nThis option is required for waveform types SQUARE, RAMP, and SINE.")
143	        ("wave-ampl", po::value<float>(&ampl)->default_value(0.3), "Baseband waveform amplitude in the range "
144	            "[0 to 0.7].")
145	        ("ref", po::value<std::string>(&ref), "Sets the source for the frequency reference. Available values "
146	            "depend on the USRP model. Typical values are 'internal', 'external', 'mimo', and 'gpsdo'.")
147	        ("pps", po::value<std::string>(&pps), "Specifies the PPS source for time synchronization. Available "
148	            "values depend on the USRP model. Typical values are 'internal', 'external', 'mimo', and 'gpsdo'.")
149	        ("otw", po::value<std::string>(&otw)->default_value("sc16"), "Specifies the over-the-wire (OTW) data "
150	            "format used for transmission between the host and the USRP device. Common values are \"sc16\" (16-bit signed "
151	            "complex) and \"sc8\" (8-bit signed complex). Using \"sc8\" can reduce network bandwidth at the cost of "
152	            "dynamic range."
153	            "\nNote, that not all conversions between CPU and OTW formats are possible.")
154	        ("channels", po::value<std::string>(&channel_list)->default_value("0"), "Specifies which channels to "
155	            "use. E.g. \"0\", \"1\", \"0,1\", etc.")
156	        ("int-n", "Use integer-N tuning for USRP RF synthesizers. With this mode, the LO can only be tuned in "
157	            "discrete steps, which are integer multiples of the reference frequency. This mode can improve phase noise "
158	            "and spurious performance at the cost of coarser frequency resolution.")
159	    ;
160	    // clang-format on
161	    po::variables_map vm;
162	    po::store(po::parse_command_line(argc, argv, desc), vm);
163	    // print the help message
164	    if (vm.count("help")) {
165	        std::cout << program_doc << std::endl;
166	        std::cout << desc << std::endl;
167	        return ~0;
168	    }
169	    po::notify(vm); // only called if --help was not requested
170	
171	    // create a usrp device
172	    std::cout << std::endl;
173	    std::cout << boost::format("Creating the usrp device with: %s...") % args
174	              << std::endl;
175	    uhd::usrp::multi_usrp::sptr usrp = uhd::usrp::multi_usrp::make(args);
176	
177	    // always select the subdevice first, the channel mapping affects the other settings
178	    if (vm.count("subdev"))
179	        usrp->set_tx_subdev_spec(subdev, uhd::usrp::multi_usrp::ALL_MBOARDS);
180	
181	    // detect which channels to use
182	    std::vector<std::string> channel_strings;
183	    std::vector<size_t> channel_nums;
184	    boost::split(channel_strings, channel_list, boost::is_any_of("\"',"));
185	    for (size_t ch = 0; ch < channel_strings.size(); ch++) {
186	        size_t chan = std::stoi(channel_strings[ch]);
187	        if (chan >= usrp->get_tx_num_channels())
188	            throw std::runtime_error("Invalid channel(s) specified.");
189	        else
190	            channel_nums.push_back(std::stoi(channel_strings[ch]));
191	    }
192	
193	    // Lock mboard clocks
194	    if (vm.count("ref")) {
195	        usrp->set_clock_source(ref);
196	    }
197	
198	    std::cout << boost::format("Using Device: %s") % usrp->get_pp_string() << std::endl;
199	
200	    // set the sample rate
201	    if (not vm.count("rate")) {
202	        std::cerr << "Please specify the sample rate with --rate" << std::endl;
203	        return ~0;
204	    }
205	    std::cout << boost::format("Setting TX Rate: %f Msps...") % (rate / 1e6) << std::endl;
206	    for (std::size_t channel : channel_nums) {
207	        usrp->set_tx_rate(rate, channel);
208	        std::cout << boost::format("Actual TX Rate: %f Msps...")
209	                         % (usrp->get_tx_rate(channel) / 1e6)
210	                  << std::endl
211	                  << std::endl;
212	    }
213	
214	    // set the center frequency
215	    if (not vm.count("freq")) {
216	        std::cerr << "Please specify the center frequency with --freq" << std::endl;
217	        return ~0;
218	    }
219	
220	    // for the const wave, set the wave freq for small samples per period
221	    if (wave_freq == 0) {
222	        if (wave_type == "CONST") {
223	            wave_freq = usrp->get_tx_rate(channel_nums.front()) / 2;
224	        } else {
225	            throw std::runtime_error(
226	                "wave freq cannot be 0 with wave type other than CONST");
227	        }
228	    }
229	
230	    // pre-compute the waveform values
231	    const wave_table_class wave_table(wave_type, ampl);
232	    const size_t step =
233	        std::lround(wave_freq / usrp->get_tx_rate(channel_nums.front()) * wave_table_len);
234	    size_t index = 0;
235	
236	    // Defer setting the frequency and LO offset until synchronization setup is complete,
237	    // configuring here only gains, bandwidth, and antenna
238	    for (std::size_t channel : channel_nums) {
239	        // set the rf gain
240	        if (vm.count("power")) {
241	            if (!usrp->has_tx_power_reference(channel)) {
242	                std::cout << "ERROR: USRP does not have a reference power API on channel "
243	                          << channel << "!" << std::endl;
244	                return EXIT_FAILURE;
245	            }
246	            std::cout << "Setting TX output power: " << power << " dBm..." << std::endl;
247	            usrp->set_tx_power_reference(power - wave_table.get_power(), channel);
248	            std::cout << "Actual TX output power: "
249	                      << usrp->get_tx_power_reference(channel) + wave_table.get_power()
250	                      << " dBm..." << std::endl;
251	            if (vm.count("gain")) {
252	                std::cout << "WARNING: If you specify both --power and --gain, "
253	                             " the latter will be ignored."
254	                          << std::endl;
255	            }
256	        } else if (vm.count("gain")) {
257	            std::cout << boost::format("Setting TX Gain: %f dB...") % gain << std::endl;
258	            usrp->set_tx_gain(gain, channel);
259	            std::cout << boost::format("Actual TX Gain: %f dB...")
260	                             % usrp->get_tx_gain(channel)
261	                      << std::endl
262	                      << std::endl;
263	        }
264	
265	        // set the analog frontend filter bandwidth
266	        if (vm.count("bw")) {
267	            std::cout << boost::format("Setting TX Bandwidth: %f MHz...") % bw
268	                      << std::endl;
269	            usrp->set_tx_bandwidth(bw, channel);
270	            std::cout << boost::format("Actual TX Bandwidth: %f MHz...")
271	                             % usrp->get_tx_bandwidth(channel)
272	                      << std::endl
273	                      << std::endl;
274	        }
275	
276	        // set the antenna
277	        if (vm.count("ant"))
278	            usrp->set_tx_antenna(ant, channel);
279	    }
280	
281	    // error when the waveform is not possible to generate
282	    if (std::abs(wave_freq) > usrp->get_tx_rate() / 2) {
283	        throw std::runtime_error("wave freq out of Nyquist zone");
284	    }
285	    if (usrp->get_tx_rate() / std::abs(wave_freq) > wave_table_len / 2) {
286	        throw std::runtime_error("wave freq too small for table");
287	    }
288	
289	    // create a transmit streamer
290	    // linearly map channels (index0 = channel0, index1 = channel1, ...)
291	    uhd::stream_args_t stream_args("fc32", otw);
292	    stream_args.channels             = channel_nums;
293	    uhd::tx_streamer::sptr tx_stream = usrp->get_tx_stream(stream_args);
294	
295	    // allocate a buffer which we re-use for each channel
296	    if (spb == 0) {
297	        spb = tx_stream->get_max_num_samps() * 10;
298	    }
299	    std::vector<std::complex<float>> buff(spb);
300	    std::vector<std::complex<float>*> buffs(channel_nums.size(), &buff.front());
301	
302	    // pre-fill the buffer with the waveform
303	    for (size_t n = 0; n < buff.size(); n++) {
304	        buff[n] = wave_table(index += step);
305	    }
306	
307	    std::cout << boost::format("Setting device timestamp to 0...") << std::endl;
308	    if (channel_nums.size() > 1) {
309	        // Sync times
310	        if (pps == "mimo") {
311	            UHD_ASSERT_THROW(usrp->get_num_mboards() == 2);
312	
313	            // make mboard 1 a slave over the MIMO Cable
314	            usrp->set_time_source("mimo", 1);
315	
316	            // set time on the master (mboard 0)
317	            usrp->set_time_now(uhd::time_spec_t(0.0), 0);
318	
319	            // sleep a bit while the slave locks its time to the master
320	            std::this_thread::sleep_for(std::chrono::milliseconds(100));
321	        } else {
322	            if (pps == "internal" or pps == "external" or pps == "gpsdo")
323	                usrp->set_time_source(pps);
324	            usrp->set_time_unknown_pps(uhd::time_spec_t(0.0));
325	            std::this_thread::sleep_for(
326	                std::chrono::seconds(1)); // wait for pps sync pulse
327	        }
328	    } else {
329	        usrp->set_time_now(0.0);
330	    }
331	
332	    // Now, that clock sync setup is complete do timed tuning of LOs and NCOs
333	    std::cout << boost::format("Setting TX Freq: %f MHz...") % (freq / 1e6) << std::endl;
334	    std::cout << boost::format("Setting TX LO Offset: %f MHz...") % (lo_offset / 1e6)
335	              << std::endl;
336	
337	    // use timed tuning for more than one channel
338	    const bool timed_tuning     = channel_nums.size() > 1;
339	    const float cmd_time_offset = 0.1;
340	
341	    if (timed_tuning) {
342	        const uhd::time_spec_t now      = usrp->get_time_now();
343	        const uhd::time_spec_t cmd_time = now + uhd::time_spec_t(cmd_time_offset);
344	        usrp->set_command_time(cmd_time);
345	    }
346	
347	    for (std::size_t channel : channel_nums) {
348	        uhd::tune_request_t tune_request(freq, lo_offset);
349	        if (vm.count("int-n"))
350	            tune_request.args = uhd::device_addr_t("mode_n=integer");
351	        usrp->set_tx_freq(tune_request, channel);
352	    }
353	
354	    // clear command time and wait to finish for timed tuning
355	    if (timed_tuning) {
356	        usrp->clear_command_time();
357	        std::this_thread::sleep_for(std::chrono::milliseconds(int64_t(
358	            1e3 * cmd_time_offset))); // wait until the command time has passed for sure
359	    }
360	
361	    for (std::size_t channel : channel_nums) {
362	        std::cout << boost::format("Actual TX Freq: %f MHz...")
363	                         % (usrp->get_tx_freq(channel) / 1e6)
364	                  << std::endl
365	                  << std::endl;
366	    }
367	
368	    // Allow for some setup time: In particular, LOs and other tuning-related
369	    // components might need some time to lock. 1 second is way more than enough
370	    // time. If there were no sleep time at all, we might see LO lock errors
371	    // as the following check does not include a polling loop.
372	    std::this_thread::sleep_for(std::chrono::seconds(1));
373	
374	    // Check Ref and LO Lock detect
375	    std::vector<std::string> sensor_names;
376	    const size_t tx_sensor_chan = channel_nums.empty() ? 0 : channel_nums[0];
377	    sensor_names                = usrp->get_tx_sensor_names(tx_sensor_chan);
378	    if (std::find(sensor_names.begin(), sensor_names.end(), "lo_locked")
379	        != sensor_names.end()) {
380	        uhd::sensor_value_t lo_locked = usrp->get_tx_sensor("lo_locked", tx_sensor_chan);
381	        std::cout << boost::format("Checking TX: %s ...") % lo_locked.to_pp_string()
382	                  << std::endl;
383	        UHD_ASSERT_THROW(lo_locked.to_bool());
384	    }
385	    const size_t mboard_sensor_idx = 0;
386	    sensor_names                   = usrp->get_mboard_sensor_names(mboard_sensor_idx);
387	    if ((ref == "mimo")
388	        and (std::find(sensor_names.begin(), sensor_names.end(), "mimo_locked")
389	             != sensor_names.end())) {
390	        uhd::sensor_value_t mimo_locked =
391	            usrp->get_mboard_sensor("mimo_locked", mboard_sensor_idx);
392	        std::cout << boost::format("Checking TX: %s ...") % mimo_locked.to_pp_string()
393	                  << std::endl;
394	        UHD_ASSERT_THROW(mimo_locked.to_bool());
395	    }
396	    if ((ref == "external")
397	        and (std::find(sensor_names.begin(), sensor_names.end(), "ref_locked")
398	             != sensor_names.end())) {
399	        uhd::sensor_value_t ref_locked =
400	            usrp->get_mboard_sensor("ref_locked", mboard_sensor_idx);
401	        std::cout << boost::format("Checking TX: %s ...") % ref_locked.to_pp_string()
402	                  << std::endl;
403	        UHD_ASSERT_THROW(ref_locked.to_bool());
404	    }
405	
406	    std::signal(SIGINT, &sig_int_handler);
407	    std::cout << "Press Ctrl + C to stop streaming..." << std::endl;
408	
409	    // Set up metadata. We start streaming a bit in the future
410	    // to allow MIMO operation:
411	    uhd::tx_metadata_t md;
412	    md.start_of_burst = true;
413	    md.end_of_burst   = false;
414	    md.has_time_spec  = true;
415	    md.time_spec      = usrp->get_time_now() + uhd::time_spec_t(0.1);
416	
417	    // send data until the signal handler gets called
418	    // or if we accumulate the number of samples specified (unless it's 0)
419	    uint64_t num_acc_samps = 0;
420	    while (true) {
421	        // Break on the end of duration or CTRL-C
422	        if (stop_signal_called) {
423	            break;
424	        }
425	        // Break when we've received nsamps
426	        if (total_num_samps > 0 and num_acc_samps >= total_num_samps) {
427	            break;
428	        }
429	
430	        // send the entire contents of the buffer
431	        num_acc_samps += tx_stream->send(buffs, buff.size(), md);
432	
433	        // fill the buffer with the waveform
434	        for (size_t n = 0; n < buff.size(); n++) {
435	            buff[n] = wave_table(index += step);
436	        }
437	
438	        md.start_of_burst = false;
439	        md.has_time_spec  = false;
440	    }
441	
442	    // send a mini EOB packet
443	    md.end_of_burst = true;
444	    tx_stream->send("", 0, md);
445	
446	    // finished
447	    std::cout << std::endl << "Done!" << std::endl << std::endl;
448	    return EXIT_SUCCESS;
449	}
450

