9	#include <algorithm>
10	#include <cmath>
11	#include <complex>
12	#include <stdexcept>
13	#include <string>
14	#include <vector>
15	
16	static const size_t wave_table_len = 8192;
17	
18	class wave_table_class
19	{
20	public:
21	    wave_table_class(const std::string& wave_type, const float ampl)
22	        : _wave_table(wave_table_len, {0.0, 0.0})
23	    {
24	        // Note: CONST, SQUARE, and RAMP only fill the I portion, since they are
25	        // amplitude-modulating signals, not phase-modulating.
26	        if (wave_type == "CONST") {
27	            // Fill with I == ampl, Q == 0
28	            std::fill(
29	                _wave_table.begin(), _wave_table.end(), std::complex<float>{ampl, 0.0});
30	            _power_dbfs = static_cast<double>(20 * std::log10(ampl));
31	        } else if (wave_type == "SQUARE") {
32	            // Fill the second half of the table with ampl, first half with
33	            // zeros
34	            std::fill(_wave_table.begin() + wave_table_len / 2,
35	                _wave_table.end(),
36	                std::complex<float>{ampl, 0.0});
37	            _power_dbfs = static_cast<double>(20 * std::log10(ampl))
38	                          - static_cast<double>(10 * std::log10(2.0));
39	        } else if (wave_type == "RAMP") {
40	            // Fill I values with ramp from -1 to 1, Q with zero
41	            float energy_acc = 0.0f;
42	            for (size_t i = 0; i < wave_table_len; i++) {
43	                _wave_table[i] = {(2.0f * i / (wave_table_len - 1) - 1.0f) * ampl, 0.0};
44	                energy_acc += std::norm(_wave_table[i]);
45	            }
46	            _power_dbfs = static_cast<double>(energy_acc / wave_table_len);
47	            // Note: The closed-form solution to the average sum of squares of
48	            // the ramp is:
49	            // 1.0 / 3 + 2.0 / (3 * N) + 1.0 / (3 * N) + 4.0 / (6 * N^2))
50	            // where N == wave_table_len, but it turns out be be less code if we
51	            // just calculate the power on the fly.
52	        } else if (wave_type == "SINE") {
53	            static const double tau = 2 * std::acos(-1.0);
54	            static const std::complex<float> J(0, 1);
55	            // Careful: i is the loop counter, not the imaginary unit
56	            for (size_t i = 0; i < wave_table_len; i++) {
57	                // Directly generate complex sinusoid (a*e^{j 2\pi i/N}). We
58	                // create a single rotation. The call site will sub-sample
59	                // appropriately to create a sine wave of it's desired frequency
60	                _wave_table[i] =
61	                    ampl * std::exp(J * static_cast<float>(tau * i / wave_table_len));
62	            }
63	            _power_dbfs = static_cast<double>(20 * std::log10(ampl));
64	        } else {
65	            throw std::runtime_error("unknown waveform type: " + wave_type);
66	        }
67	    }
68	
69	    inline std::complex<float> operator()(const size_t index) const
70	    {
71	        return _wave_table[index % wave_table_len];
72	    }
73	
74	    //! Return the signal power in dBFS
75	    inline double get_power() const
76	    {
77	        return _power_dbfs;
78	    }
79	
80	private:
81	    std::vector<std::complex<float>> _wave_table;
82	    double _power_dbfs;
83	};
