88	        ("rate,r", po::value<double>(&rate)->default_value(100e6/16), "TX sample rate in samples/second. Note "
89	            "that each USRP device only supports a set of discrete sample rates, which depend on the hardware model and "
90	            "configuration. If you request a rate that is not supported, the USRP device will automatically select and "
91	            "use the closest available rate.")
92	        ("ampl", po::value<float>(&ampl)->default_value(float(0.3)), "Value assigned to both I and Q "
93	            "component of each complex baseband sample (i.e., each sample is ampl + j*ampl).")
94	        ("freq,f", po::value<double>(&freq)->default_value(0), "RF center frequency in Hz.")
95	        ("gain", po::value<double>(&gain)->default_value(0), "TX gain for the RF chain in dB.")
96	        ("dilv", "Disables inner-loop verbose status prints.")
97	        ("channels", po::value<std::string>(&channel_list)->default_value("0"), "Specifies which channels to "
98	            "use. E.g. \"0\", \"1\", \"0,1\", etc.")
99	        ("int-n", "Use integer-N tuning for USRP RF synthesizers. With this mode, the LO can only be tuned in "
100	            "discrete steps, which are integer multiples of the reference frequency. This mode can improve phase noise "
101	            "and spurious performance at the cost of coarser frequency resolution.")
102	        ("subdev", po::value<std::string>(&subdev), "TX subdevice configuration string, selecting which RF "
103	            "path to use for the receive channel."
104	            "\nThis example always uses channel 0; use --subdev to select which RF path is mapped to channel 0."
105	            "\nThe format and available values depend on your USRP model. If not specified, the default subdevice will be "
106	            "used."
107	            "\nExample:"
108	            "\nAssume we have an X310 with two UBX daughterboards installed."
109	            "\nBy default, channel 0 maps to A:0 (1st UBX in slot A, RF TX 0), which is equivalent to --subdev \"A:0\"."
110	            "\nTo use the 2nd UBX (slot B, RF TX 0), specify --subdev \"B:0\".")
111	        ("ref", po::value<std::string>(&ref), "Sets the source for the frequency reference. Available values "
112	            "depend on the USRP model. Typical values are 'internal', 'external', 'mimo', and 'gpsdo'.")
113	        ("lo-offset", po::value<double>(&lo_offset)->default_value(0.0),
114	            "LO offset for the frontend in Hz.")
115	        ("bw", po::value<double>(&bw), "Sets the analog frontend filter bandwidth for the TX path in Hz. Not "
116	            "all USRP devices support programmable bandwidth; if an unsupported value is requested, the device will use "
