143	    }
144	
145	    // always select the subdevice first, the channel mapping affects the other settings
146	    if (vm.count("subdev"))
147	        usrp->set_tx_subdev_spec(subdev);
148	
149	    std::cout << boost::format("Using Device: %s") % usrp->get_pp_string() << std::endl;
150	
151	    // detect which channels to use
152	    std::vector<std::string> channel_strings;
153	    std::vector<size_t> channel_nums;
154	    boost::split(channel_strings, channel_list, boost::is_any_of("\"',"));
155	    for (size_t ch = 0; ch < channel_strings.size(); ch++) {
156	        size_t chan = std::stoi(channel_strings[ch]);
157	        if (chan >= usrp->get_tx_num_channels()) {
158	            throw std::runtime_error("Invalid channel(s) specified.");
159	        } else
160	            channel_nums.push_back(std::stoi(channel_strings[ch]));
161	    }
162	
163	    // set the tx sample rate
164	    std::cout << boost::format("Setting TX Rate: %f Msps...") % (rate / 1e6) << std::endl;
165	    usrp->set_tx_rate(rate);
166	    std::cout << boost::format("Actual TX Rate: %f Msps...") % (usrp->get_tx_rate() / 1e6)
167	              << std::endl
168	              << std::endl;
169	
170	    // set the center frequency
171	    if (not vm.count("freq")) {
172	        std::cerr << "Please specify the center frequency with --freq" << std::endl;
173	        return ~0;
174	    }
175	
176	    std::cout << "Requesting TX Freq: " << freq / 1e6 << " MHz..." << std::endl;
177	    std::cout << "Requesting TX LO Offset: " << lo_offset / 1e6 << " MHz..." << std::endl;
178	
179	    for (size_t i = 0; i < channel_nums.size(); i++) {
180	        uhd::tune_request_t tune_request;
181	        tune_request = uhd::tune_request_t(freq, lo_offset);
182	
183	        if (vm.count("int-n"))
184	            tune_request.args = uhd::device_addr_t("mode_n=integer");
185	        usrp->set_tx_freq(tune_request, channel_nums[i]);
186	    }
187	    std::cout << "Actual TX Freq: " << (usrp->get_tx_freq(channel_nums.front()) / 1e6)
188	              << " MHz..." << std::endl
189	              << std::endl;
190	
191	    std::cout << "Requesting TX Gain: " << gain << " dB ..." << std::endl;
192	    for (size_t i = 0; i < channel_nums.size(); i++)
193	        usrp->set_tx_gain(gain, channel_nums[i]);
194	    std::cout << "Actual TX Gain: " << (usrp->get_tx_gain(channel_nums.front())) << "..."
195	              << std::endl
196	              << std::endl;
197	
198	    // set the analog frontend filter bandwidth
199	    if (vm.count("bw")) {
200	        std::cout << "Requesting TX Bandwidth: " << (bw / 1e6) << " MHz..." << std::endl;
201	        usrp->set_tx_bandwidth(bw);
202	        std::cout << "Actual TX Bandwidth: "
203	                  << usrp->get_tx_bandwidth(channel_nums.front()) / 1e6 << " MHz..."
204	                  << std::endl
205	                  << std::endl;
206	    }
207	
208	    std::cout << boost::format("Setting device timestamp to 0...") << std::endl;
209	    usrp->set_time_now(uhd::time_spec_t(0.0));
210	
211	    // create a transmit streamer
212	    uhd::stream_args_t stream_args("fc32"); // complex floats
213	    stream_args.channels             = channel_nums;
214	    uhd::tx_streamer::sptr tx_stream = usrp->get_tx_stream(stream_args);
215	
216	    // allocate buffer with data to send
217	    const size_t spb = tx_stream->get_max_num_samps();
218	
219	    std::vector<std::complex<float>> buff(spb, std::complex<float>(ampl, ampl));
220	    std::vector<std::complex<float>*> buffs(channel_nums.size(), &buff.front());
221	
222	    std::signal(SIGINT, &sig_int_handler);
223	    if (repeat)
224	        std::cout << "Press Ctrl + C to quit..." << std::endl;
225	
226	    double time_to_send = seconds_in_future;
227	
228	    do {
229	        // setup metadata for the first packet
230	        uhd::tx_metadata_t md;
231	        md.start_of_burst = true;
232	        md.end_of_burst   = false;
233	        md.has_time_spec  = true;
234	        md.time_spec      = uhd::time_spec_t(time_to_send);
235	
236	        // the first call to send() will block this many seconds before sending:
237	        double timeout = std::max(rep_rate, seconds_in_future)
238	                         + 0.1; // timeout (delay before transmit + padding)
239	
240	        size_t num_acc_samps = 0; // number of accumulated samples
241	        while (num_acc_samps < total_num_samps) {
242	            size_t samps_to_send = total_num_samps - num_acc_samps;
243	            if (samps_to_send > spb) {
244	                samps_to_send = spb;
245	            } else {
246	                md.end_of_burst = true;
247	            }
248	
249	            // send a single packet
250	            size_t num_tx_samps = tx_stream->send(buffs, samps_to_send, md, timeout);
251	            // do not use time spec for subsequent packets
252	            md.has_time_spec  = false;
253	            md.start_of_burst = false;
254	
255	            if (num_tx_samps < samps_to_send) {
256	                std::cerr << "Send timeout..." << std::endl;
257	                if (stop_signal_called) {
258	                    exit(EXIT_FAILURE);
259	                }
260	            }
261	
262	            if (verbose) {
263	                std::cout << boost::format("Sent packet: %u samples") % num_tx_samps
264	                          << std::endl;
265	            }
266	
267	            num_acc_samps += num_tx_samps;
268	        }
269	
270	        time_to_send += rep_rate;
271	
272	        std::cout << std::endl << "Waiting for async burst ACK... " << std::flush;
273	        uhd::async_metadata_t async_md;
274	        size_t acks = 0;
275	        // loop through all messages for the ACK packets (may have underflow messages in
276	        // queue)
277	        while (acks < channel_nums.size()
278	               and tx_stream->recv_async_msg(async_md, seconds_in_future)) {
279	            if (async_md.event_code == uhd::async_metadata_t::EVENT_CODE_BURST_ACK) {
280	                acks++;
281	            }
282	        }
283	        std::cout << (acks == channel_nums.size() ? "success" : "fail") << std::endl;
284	    } while (not stop_signal_called and repeat);
285	
286	    // finished
287	    std::cout << std::endl << "Done!" << std::endl << std::endl;
288	
289	    return EXIT_SUCCESS;
290	}
